settings.custom_css:
.box-destaque {
  background-color: #4A1E1E; /* vinho escuro */
  color: #fff;
  padding: 20px;
  border-radius: 15px;
  font-family: 'Poppins', sans-serif;
  font-weight: 500;
  line-height: 1.4;
  max-width: 500px;
  text-align: left;
  margin: 0 auto;
}

.box-destaque .numero {
  color: #E94A3F; /* vermelho destacado */
  font-weight: 700;
  font-size: 3em; /* tamanho grande para desktop */
  line-height: 1;
  margin-right: 5px;
  display: inline-block;
  vertical-align: middle;
}

/* Responsividade */
@media (max-width: 1024px) {
  .box-destaque {
    max-width: 90%;
    padding: 18px;
    font-size: 0.95rem;
  }

  .box-destaque .numero {
    font-size: 2.5em;
  }
}

@media (max-width: 768px) {
  .box-destaque {
    padding: 15px;
    font-size: 0.9rem;
  }

  .box-destaque .numero {
    font-size: 2em;
  }
}

@media (max-width: 480px) {
  .box-destaque {
    padding: 12px;
    font-size: 0.85rem;
  }

  .box-destaque .numero {
    font-size: 1.8em;
  }
}

